#include <CL/cl.h>

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__attribute__((reqd_work_group_size(256, 1, 1)))
void pgain_kernel(
    global Point_Struct* p,
    global float* coord,
    global float* work_mem,
    global int* center_table,
    global char* switch_membership,
    local float* local_coord,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    int tid = get_local_id(0);

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        int ct = center_table[assign];
        if (ct >= 0 && ct < K) {
            work_mem[i * (K + 1) + ct] += current_cost - x_cost;
        }
    }
}

__attribute__((reqd_work_group_size(256, 1, 1)))
void update_centers_kernel(
    global Point_Struct* p,
    global float* coord,
    global float* work_mem,
    global int* center_table,
    global char* switch_membership,
    global float* gl_lower,
    global int* is_center,
    const int num,
    const int dim,
    const long x,
    const int K,
    const float z)
{
    int i = get_global_id(0);
    if (i >= num) return;

    if (is_center[i]) {
        float low = z;
        int ct = center_table[i];
        if (ct >= 0 && ct < K) {
            for (int j = 0; j < num; j++) {
                low += work_mem[j * (K + 1) + ct];
            }
            gl_lower[ct] = low;

            if (low > 0) {
                work_mem[i * (K + 1) + K] -= low;
            }
        }
    }
}

__attribute__((reqd_work_group_size(256, 1, 1)))
void apply_changes_kernel(
    global Point_Struct* p,
    global float* coord,
    global float* work_mem,
    global int* center_table,
    global char* switch_membership,
    global float* gl_lower,
    global int* is_center,
    const int num,
    const int dim,
    const long x,
    const int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    int assign = p[i].assign;
    int ct = center_table[assign];
    bool close_center = (ct >= 0 && ct < K && gl_lower[ct] > 0);

    if (switch_membership[i] == 1 || close_center) {
        float dist = 0.0f;
        for (int d = 0; d < dim; d++) {
            float diff = coord[d * num + i] - coord[d * num + x];
            dist += diff * diff;
        }
        p[i].cost = p[i].weight * dist;
        p[i].assign = x;
    }

    if (is_center[i] && ct >= 0 && ct < K && gl_lower[ct] > 0) {
        is_center[i] = 0;
    }

    if (i == x) {
        is_center[i] = 1;
    }
}
